noncompliant:
#include <unistd.h>
#include <fstream>

void readFile(const char* filename) {
    // Noncompliant - check and use are separated (TOCTOU vulnerability)
    if (access(filename, R_OK) == 0) {  // Check if file is readable
        // Time gap where file permissions could change
        std::ifstream file(filename);     // Use the file
        // ... process file
    }
}

void writeFile(const char* filename) {
    // Noncompliant - checking existence then opening
    if (access(filename, F_OK) != 0) {   // Check if file doesn't exist
        std::ofstream file(filename);     // Create and open file
        // ... write to file
    }
}

compliant:
#include <fstream>
#include <cerrno>

void readFile(const char* filename) {
    // Compliant - directly attempt the operation
    std::ifstream file(filename);
    if (!file) {
        // Handle error appropriately
        perror("Failed to open file");
        return;
    }
    // ... process file
}

void writeFile(const char* filename) {
    // Compliant - use appropriate file opening mode
    std::ofstream file(filename, std::ios::out | std::ios::excl);  // Fail if exists
    if (!file) {
        // Handle error appropriately
        perror("Failed to create file");
        return;
    }
    // ... write to file
}
